SET		FST_ACT_CD = #{fstActCd}
		, FST_ACT_REMARK = #{fstActRemark}
		, SND_ACT_CD = #{sndActCd}
		, SND_ACT_REMARK = #{sndActRemark}
WHERE	CONTRACT_NUM = #{contractNum}

